const env = require('frontend-env');

const { NODE_COUNTRY_UPDATES, PRODUCTION } = env;

const {
  initChecker,
  updateCountriesData,
  getCountriesData,
} = require('../utils/update-data');

// Set up the updates checker. Can be disabled by setting the NODE_COUNTRY_UPDATES to falsy value
const useUpdates = initChecker(NODE_COUNTRY_UPDATES, true);

const UPDATE_INTERVAL = 60 * 60 * 1000; // 1 hour

if (PRODUCTION && useUpdates) {
  void updateCountriesData();

  // Random jitter offsets the recurring cycle so that multiple instances
  // started simultaneously don't all hit the API at the same time.
  const jitter = Math.floor(Math.random() * UPDATE_INTERVAL);

  setTimeout(() => {
    void updateCountriesData();
    setInterval(updateCountriesData, UPDATE_INTERVAL);
  }, UPDATE_INTERVAL + jitter);
}

/**
 * Returns the available data for a single country
 * @param {import('../types/index').CountryId} countryId
 */
const getCountryConfig = (countryId) => getCountriesData()[countryId];

module.exports = getCountryConfig;
